class Solution {
    public long validSubstringCount(String word1, String word2) {
        int n = word1.length(), m = word2.length();
        long res = 0;
        int[] cnt1 = new int[26], cnt2 = new int[26];
        for (int i = 0; i < m; i++) cnt2[word2.charAt(i) - 'a']++;
        for (int i = 0; i < n; i++) {
            cnt1[word1.charAt(i) - 'a']++;
            if (i >= m) cnt1[word1.charAt(i - m) - 'a']--;
            boolean ok = true;
            for (int j = 0; j < 26; j++) if (cnt1[j] < cnt2[j]) ok = false;
            if (ok) res += n - i;
        }
        return res;
    }
}
